"use client";

import Link from "next/link";
import { useState } from "react";
import { Menu, X } from "lucide-react";

import { Button } from "./ui/button";

const navLinks = [
  { href: "#about", label: "コミュニティ紹介" },
  { href: "#founders", label: "メンター" },
  { href: "#activity", label: "活動プログラム" },
  { href: "#contact", label: "相談する" },
];

export function Header() {
  const [menuOpen, setMenuOpen] = useState(false);

  const handleNavigate = () => setMenuOpen(false);

  return (
    <header className="fixed left-0 right-0 top-0 z-50 border-border/60 bg-white/80 shadow-sm backdrop-blur-xl">
      <div className="mx-auto flex h-16 max-w-5xl items-center justify-between px-4 sm:px-6">
        <Link
          href="/"
          className="text-lg font-semibold tracking-tight text-foreground"
        >
          We部{" "}
          <span className="text-sm font-normal text-muted-foreground">
            community
          </span>
        </Link>
        <nav className="hidden items-center gap-6 text-sm font-medium text-muted-foreground md:flex">
          {navLinks.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className="transition-colors hover:text-foreground"
            >
              {link.label}
            </Link>
          ))}
        </nav>
        <div className="flex items-center gap-2">
          <Button
            asChild
            size="sm"
            className="hidden bg-primary/90 text-primary-foreground shadow-sm hover:bg-primary sm:inline-flex"
          >
            <a href="#contact">まずは話を聞く</a>
          </Button>
          <button
            type="button"
            className="inline-flex items-center justify-center rounded-md border border-border/70 bg-white/70 p-2 text-foreground shadow-sm transition hover:bg-white md:hidden"
            onClick={() => setMenuOpen((prev) => !prev)}
            aria-label="ナビゲーションメニュー"
            aria-expanded={menuOpen}
          >
            {menuOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </button>
        </div>
      </div>
      {menuOpen && (
        <div className="md:hidden border-t border-border/60 bg-white/95 shadow-sm">
          <div className="mx-auto flex max-w-5xl flex-col gap-3 px-4 py-4 text-sm font-medium text-muted-foreground">
            {navLinks.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                className="rounded-lg px-2 py-2 transition hover:bg-primary/10 hover:text-foreground"
                onClick={handleNavigate}
              >
                {link.label}
              </Link>
            ))}
            <Button
              asChild
              className="w-full bg-primary text-primary-foreground shadow-sm hover:bg-primary/90"
              onClick={handleNavigate}
            >
              <a href="#contact">まずは話を聞く</a>
            </Button>
          </div>
        </div>
      )}
    </header>
  );
}
